const body = $json.body ?? {};
const data = body.data ?? {};
const key = data.key ?? {};
const message = data.message ?? {};
const remoteJid = String(key.remoteJid ?? '').trim();
const phone = remoteJid.replace('@s.whatsapp.net', '').replace(/\D/g, '');
const messageId = String(key.id ?? data.id ?? '').trim();
const event = String(body.event ?? body.type ?? '').trim();
const fromMe = Boolean(key.fromMe);
const pushNameRaw = body.pushName ?? data.pushName ?? key.pushName ?? data.sender?.pushName ?? data.sender?.name ?? '';

function toText(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function collapseSpaces(value) {
  return toText(value).replace(/\s+/g, ' ').trim();
}

function normalize(value) {
  return collapseSpaces(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function sanitizeName(value) {
  return collapseSpaces(value).replace(/[|]+/g, ' ').replace(/\s+/g, ' ').trim();
}

function isLikelyEmojiOnly(value) {
  const clean = toText(value).replace(/\s+/g, '');
  if (!clean) return false;
  return !/[0-9A-Za-z??-??]/.test(clean);
}

function validateName(value) {
  const sanitized = sanitizeName(value);
  const normalized = normalize(sanitized);
  if (!sanitized || !normalized) return { valid: false, full: '', first: '' };
  if (['null', 'undefined', 'desconhecido', 'unknown', 'sem nome', 'semnome', 'nao informado', 'naoinformado'].includes(normalized)) {
    return { valid: false, full: '', first: '' };
  }
  if (/^\d+$/.test(normalized)) return { valid: false, full: '', first: '' };
  if (normalized === phone || normalized.replace(/\s+/g, '') === phone) return { valid: false, full: '', first: '' };
  if (isLikelyEmojiOnly(sanitized)) return { valid: false, full: '', first: '' };
  const words = sanitized.split(/\s+/).filter(Boolean);
  if (!words.length) return { valid: false, full: '', first: '' };
  const first = words[0];
  if (!/[A-Za-z??-??]/.test(first)) return { valid: false, full: '', first: '' };
  return {
    valid: true,
    full: words.join(' '),
    first,
  };
}

const conversation = toText(message.conversation);
const extendedText = toText(message.extendedTextMessage?.text);
const imageCaption = toText(message.imageMessage?.caption);
const videoCaption = toText(message.videoMessage?.caption);
const documentCaption = toText(message.documentWithCaptionMessage?.message?.documentMessage?.caption);
const text = conversation || extendedText || imageCaption || videoCaption || documentCaption;

const audio = message.audioMessage ?? null;
const image = message.imageMessage ?? null;
const audioUrl = toText(audio?.url);
const imageUrl = toText(image?.url);
const audioMime = toText(audio?.mimetype);
const imageMime = toText(image?.mimetype);
const mediaType = audioUrl ? 'audio' : imageUrl ? 'image' : 'text';
const hasSupportedContent = Boolean(text || audioUrl || imageUrl);

const captionNormalized = normalize(imageCaption);
const weakCaptions = new Set(['', 'oi', 'ola', 'olha', 'veja', 'segue', 'foto', 'imagem', 'print', 'anexo', 'isso', 'aqui', 'segue ai']);
const captionWordCount = captionNormalized ? captionNormalized.split(' ').length : 0;
const imageNeedsAnalysis = mediaType === 'image' && (!imageCaption || weakCaptions.has(captionNormalized) || captionWordCount <= 1);
const receiptHint = /comprovante|pix|pagamento|transferencia|recibo/.test(captionNormalized);
const shouldProcess = !fromMe && Boolean(phone) && hasSupportedContent;

const pushNameInfo = validateName(pushNameRaw);

return [{
  json: {
    event,
    instance_name: 'maximus',
    unit_slug: 'maximus-02',
    message_id: messageId,
    remote_jid: remoteJid,
    phone,
    from_me: fromMe,
    media_type: mediaType,
    message_text: text,
    audio_url: audioUrl,
    audio_mime: audioMime,
    image_url: imageUrl,
    image_mime: imageMime,
    image_caption: imageCaption,
    image_needs_analysis: imageNeedsAnalysis,
    image_receipt_hint: receiptHint,
    has_supported_content: hasSupportedContent,
    should_process: shouldProcess,
    push_name: sanitizeName(pushNameRaw),
    customer_name: pushNameInfo.full,
    customer_first_name: pushNameInfo.first,
    name_source: pushNameInfo.valid ? 'pushName' : 'unknown',
    name_is_valid: pushNameInfo.valid,
    started_at_ms: Date.now(),
    usage_components: [],
    raw: body,
  },
}];

return [{
  json: {
    ...$('Normalizar Entrada').first().json,
  },
}];

return [{
  json: {
    ...$('Normalizar Entrada').first().json,
  },
}];

return [{
  json: {
    ...$('Normalizar Entrada').first().json,
  },
}];

const source = $json ?? {};
const base64 = String(
  source.base64 ??
  source.message?.base64 ??
  source.data?.base64 ??
  ''
).trim();

if (!base64) {
  throw new Error('A Evolution API nao retornou base64 da midia.');
}

const mime = String(source.mimetype ?? source.mimeType ?? source.message?.mimetype ?? '').trim() || 'application/octet-stream';
const fileName = String(source.fileName ?? source.filename ?? source.message?.fileName ?? source.message?.filename ?? 'media.bin').trim();

return [{
  json: {
    ...$('Normalizar Entrada').first().json,
    media_download_meta: {
      mime,
      file_name: fileName,
    },
  },
  binary: {
    data: {
      data: base64,
      mimeType: mime,
      fileName,
    },
  },
}];

const normalized = $('Normalizar Entrada').first().json;
const transcription = $('Transcrever Audio').first().json ?? {};

function extractUsage(value) {
  if (!value || typeof value !== 'object') return null;
  const usage = value.usage ?? value.tokenUsage ?? value.response_metadata?.tokenUsage ?? value.response_metadata?.usage ?? null;
  if (!usage || typeof usage !== 'object') return null;
  return {
    input_tokens: Number(usage.input_tokens ?? usage.prompt_tokens ?? usage.inputTokens ?? 0) || 0,
    cached_input_tokens: Number(usage.cached_input_tokens ?? usage.cachedPromptTokens ?? usage.cachedInputTokens ?? 0) || 0,
    output_tokens: Number(usage.output_tokens ?? usage.completion_tokens ?? usage.outputTokens ?? 0) || 0,
    reasoning_tokens: Number(usage.reasoning_tokens ?? usage.reasoningTokens ?? 0) || 0,
  };
}

const transcript = String(
  transcription.text ??
  transcription.transcript ??
  transcription.output_text ??
  transcription.output ??
  ''
).trim();

const componentUsage = extractUsage(transcription);
const components = Array.isArray(normalized.usage_components) ? [...normalized.usage_components] : [];
if (componentUsage) {
  components.push({
    kind: 'audio_transcription',
    model: 'gpt-4o-mini-transcribe',
    ...componentUsage,
  });
}

return [{
  json: {
    ...normalized,
    usage_components: components,
    final_message_text: transcript || 'audio sem transcricao confirmada',
    media_summary: transcript ? 'Audio transcrito do cliente.' : 'Audio recebido sem transcricao confirmada.',
    audio_transcribed: Boolean(transcript),
    image_analysis_used: false,
  },
}];

const source = $json ?? {};
const base64 = String(
  source.base64 ??
  source.message?.base64 ??
  source.data?.base64 ??
  ''
).trim();

if (!base64) {
  throw new Error('A Evolution API nao retornou base64 da midia.');
}

const mime = String(source.mimetype ?? source.mimeType ?? source.message?.mimetype ?? '').trim() || 'application/octet-stream';
const fileName = String(source.fileName ?? source.filename ?? source.message?.fileName ?? source.message?.filename ?? 'media.bin').trim();

return [{
  json: {
    ...$('Normalizar Entrada').first().json,
    media_download_meta: {
      mime,
      file_name: fileName,
    },
  },
  binary: {
    data: {
      data: base64,
      mimeType: mime,
      fileName,
    },
  },
}];

const normalized = $('Normalizar Entrada').first().json;
const analysis = $('Analisar Imagem').first().json ?? {};

function extractUsage(value) {
  if (!value || typeof value !== 'object') return null;
  const usage = value.usage ?? value.tokenUsage ?? value.response_metadata?.tokenUsage ?? value.response_metadata?.usage ?? null;
  if (!usage || typeof usage !== 'object') return null;
  return {
    input_tokens: Number(usage.input_tokens ?? usage.prompt_tokens ?? usage.inputTokens ?? 0) || 0,
    cached_input_tokens: Number(usage.cached_input_tokens ?? usage.cachedPromptTokens ?? usage.cachedInputTokens ?? 0) || 0,
    output_tokens: Number(usage.output_tokens ?? usage.completion_tokens ?? usage.outputTokens ?? 0) || 0,
    reasoning_tokens: Number(usage.reasoning_tokens ?? usage.reasoningTokens ?? 0) || 0,
  };
}

function collectText(value) {
  if (typeof value === 'string') return value.trim();
  if (Array.isArray(value)) return value.map(collectText).filter(Boolean).join(' ');
  if (value && typeof value === 'object') {
    return [
      collectText(value.text),
      collectText(value.output_text),
      collectText(value.content),
      collectText(value.summary),
      collectText(value.answer),
      collectText(value.response),
    ].filter(Boolean).join(' ');
  }
  return '';
}

const analysisText = collectText(analysis).replace(/\s+/g, ' ').trim();
const pieces = [String(normalized.image_caption ?? '').trim(), analysisText].filter(Boolean);
const usage = extractUsage(analysis);
const components = Array.isArray(normalized.usage_components) ? [...normalized.usage_components] : [];

if (usage) {
  components.push({
    kind: 'image_analysis',
    model: 'gpt-5-mini',
    ...usage,
  });
}

return [{
  json: {
    ...normalized,
    usage_components: components,
    final_message_text: pieces.join(' | ') || 'imagem enviada pelo cliente',
    media_summary: analysisText ? 'Imagem analisada: ' + analysisText : 'Imagem enviada pelo cliente.',
    image_analysis_used: true,
    image_analysis_text: analysisText,
  },
}];

return [{
  json: {
    ...$json,
    final_message_text: String($json.image_caption ?? $json.message_text ?? '').trim() || 'imagem enviada pelo cliente',
    media_summary: String($json.image_caption ?? '').trim() ? 'Imagem recebida com legenda do cliente.' : 'Imagem enviada pelo cliente.',
    image_analysis_used: false,
  },
}];

return [{
  json: {
    ...$json,
    final_message_text: String($json.message_text ?? '').trim(),
    media_summary: '',
    image_analysis_used: false,
  },
}];

const input = $json;
const customerContext = $('Buscar Cliente e Pedido').first().json ?? {};
const unit = $('Buscar Unidade Floresta1').first().json ?? null;
const settings = $('Buscar Configuracoes Floresta').first().json ?? null;
const botConfig = $('Buscar Bot Config').first().json ?? { intents: [], patterns: [], templates: [] };
const session = $('Buscar Sessao').first().json ?? {};
const zones = $('Buscar Zonas Entrega').all().map((item) => item.json).filter(Boolean);
const products = $('Buscar Produtos Unidade').all().map((item) => item.json).filter(Boolean);
const paymentRows = $('Buscar Pagamentos Recentes').all().map((item) => item.json).filter(Boolean);

const TIMEZONE = 'America/Santarem';
const DAY_ORDER = ['domingo', 'segunda', 'terca', 'quarta', 'quinta', 'sexta', 'sabado'];
const DAY_LABELS = {
  domingo: 'domingo',
  segunda: 'segunda-feira',
  terca: 'terca-feira',
  quarta: 'quarta-feira',
  quinta: 'quinta-feira',
  sexta: 'sexta-feira',
  sabado: 'sabado',
};
const INTENT_LABELS = {
  business_hours: 'horario',
  order_status: 'status do pedido',
  delivery_fee: 'taxa de entrega',
  delivery_area: 'area de entrega',
  delivery_eta: 'prazo de entrega',
  address_location: 'endereco',
  payment_methods: 'formas de pagamento',
  menu_link: 'cardapio',
  pickup_dinein: 'retirada ou consumo no local',
  product_availability: 'disponibilidade de produto',
};
const STATUS_LABELS = {
  received: 'recebido',
  accepted: 'aceito',
  in_preparation: 'em preparo',
  ready: 'pronto',
  ready_for_pickup: 'pronto para retirada',
  out_for_delivery: 'saiu para entrega',
  delivered: 'entregue',
  delivered_to_table: 'entregue na mesa',
  picked_up: 'retirado',
  cancelled: 'cancelado',
  driver_on_way: 'entregador a caminho',
  driver_nearby: 'entregador proximo',
  arrived: 'pedido chegou',
  pending: 'pendente',
  paid: 'pago',
  paid_online: 'pago online',
  paid_on_delivery: 'pagamento na entrega',
  unpaid: 'pagamento pendente',
  refunded: 'estornado',
};
const YES_WORDS = new Set(['sim', 's', 'isso', 'isso mesmo', 'pode ser', 'pode', 'quero']);
const NO_WORDS = new Set(['nao', 'n', 'negativo', 'deixa', 'nao precisa']);

function toText(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function collapseSpaces(value) {
  return toText(value).replace(/\s+/g, ' ').trim();
}

function normalize(value) {
  return collapseSpaces(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function sanitizeName(value) {
  return collapseSpaces(value).replace(/[|]+/g, ' ').replace(/\s+/g, ' ').trim();
}

function isLikelyEmojiOnly(value) {
  const clean = toText(value).replace(/\s+/g, '');
  if (!clean) return false;
  return !/[0-9A-Za-z??-??]/.test(clean);
}

function validateName(value) {
  const sanitized = sanitizeName(value);
  const normalized = normalize(sanitized);
  const phone = toText(input.phone);
  if (!sanitized || !normalized) return { valid: false, full: '', first: '' };
  if (['null', 'undefined', 'desconhecido', 'unknown', 'sem nome', 'semnome', 'nao informado', 'naoinformado'].includes(normalized)) {
    return { valid: false, full: '', first: '' };
  }
  if (/^\d+$/.test(normalized)) return { valid: false, full: '', first: '' };
  if (normalized === phone || normalized.replace(/\s+/g, '') === phone) return { valid: false, full: '', first: '' };
  if (isLikelyEmojiOnly(sanitized)) return { valid: false, full: '', first: '' };
  const words = sanitized.split(/\s+/).filter(Boolean);
  if (!words.length) return { valid: false, full: '', first: '' };
  const first = words[0];
  if (!/[A-Za-z??-??]/.test(first)) return { valid: false, full: '', first: '' };
  return {
    valid: true,
    full: words.join(' '),
    first,
  };
}

function money(value) {
  const number = Number(value);
  if (!Number.isFinite(number)) return '';
  return 'R$ ' + number.toFixed(2).replace('.', ',');
}

function pickTemplate(intentCode, variantKey) {
  return (botConfig.templates || []).find((item) =>
    item.enabled !== false &&
    item.intent_code === intentCode &&
    item.variant_key === variantKey
  )?.message_template ?? '';
}

function applyTemplate(template, values) {
  return String(template || '')
    .replace(/\{\{\s*([a-zA-Z0-9_]+)\s*\}\}/g, (_, key) => {
      const value = values[key];
      return value === null || value === undefined ? '' : String(value);
    })
    .replace(/\s+/g, ' ')
    .trim();
}

function toStatusLabel(value) {
  const raw = normalize(value);
  return STATUS_LABELS[raw] ?? toText(value);
}

function getLocalDate() {
  return new Date(new Date().toLocaleString('en-US', { timeZone: TIMEZONE }));
}

function greetingPeriod() {
  const local = getLocalDate();
  const hour = local.getHours();
  if (hour >= 5 && hour <= 11) return 'Bom dia';
  if (hour >= 12 && hour <= 17) return 'Boa tarde';
  return 'Boa noite';
}

function weekdayName(offsetDays = 0) {
  const local = getLocalDate();
  local.setDate(local.getDate() + offsetDays);
  return DAY_ORDER[local.getDay()];
}

function hoursByDay(dayCode) {
  const rows = Array.isArray(unit?.business_hours) ? unit.business_hours : [];
  const row = rows.find((item) => item?.day === dayCode);
  if (!row) return { open: false, text: 'fechado', row: null };
  const periods = Array.isArray(row.periods) ? row.periods : [];
  if (!row.open || !periods.length) return { open: false, text: 'fechado', row };
  return {
    open: true,
    text: periods.map((period) => period.opensAt + ' as ' + period.closesAt).join(' e '),
    row,
  };
}

function nextOpeningText() {
  for (let offset = 1; offset <= 7; offset += 1) {
    const dayCode = weekdayName(offset);
    const info = hoursByDay(dayCode);
    if (info.open) {
      return 'Proximo horario: ' + DAY_LABELS[dayCode] + ' ' + info.text + '.';
    }
  }
  return '';
}

const sessionState = toText(session.current_state || 'idle');
const sessionPayload = session.state_payload ?? {};
const sessionNameInfo = validateName(sessionPayload.customer_name || sessionPayload.customer_first_name);
const supabaseNameInfo = validateName(customerContext.customer?.name || customerContext.customer?.first_name);
const pushNameInfo = validateName(input.customer_name || input.push_name);
const messageNameInfo = validateName(input.final_message_text || input.message_text);

let resolvedNameInfo = supabaseNameInfo;
let resolvedNameSource = 'supabase';
if (!resolvedNameInfo.valid && pushNameInfo.valid) {
  resolvedNameInfo = pushNameInfo;
  resolvedNameSource = 'pushName';
}
if (!resolvedNameInfo.valid && sessionNameInfo.valid) {
  resolvedNameInfo = sessionNameInfo;
  resolvedNameSource = 'session';
}

if (sessionState === 'aguardando_nome' && messageNameInfo.valid) {
  resolvedNameInfo = messageNameInfo;
  resolvedNameSource = 'message_text';
}

const hasValidName = resolvedNameInfo.valid;
const customerName = hasValidName ? resolvedNameInfo.full : '';
const customerFirstName = hasValidName ? resolvedNameInfo.first : '';
const customerData = customerContext.customer ?? null;

function maybeWithName(text, options = {}) {
  const clean = collapseSpaces(text);
  if (!clean) return '';
  if (!hasValidName || options.skipName) return clean;
  if (options.forceName) {
    return collapseSpaces(customerFirstName + ', ' + clean.charAt(0).toLowerCase() + clean.slice(1));
  }
  return clean;
}

function prefixForFirstTurn(text, options = {}) {
  const clean = collapseSpaces(text);
  if (!clean) return '';
  const shouldGreet = !sessionPayload.greeted_at;
  if (!shouldGreet) return clean;
  const greeting = greetingPeriod();
  const intro = hasValidName ? (greeting + ', ' + customerFirstName + '.') : (greeting + '.');
  if (options.includeIdentity) {
    return collapseSpaces(intro + ' Sou o Maximus, atendente da hamburgueria. ' + clean);
  }
  return collapseSpaces(intro + ' ' + clean);
}

function buildHoursReply(messageNormalized) {
  let requestedDay = '';
  for (const dayCode of DAY_ORDER) {
    if (messageNormalized.includes(dayCode)) {
      requestedDay = dayCode;
      break;
    }
  }
  if (!requestedDay && messageNormalized.includes('amanha')) {
    requestedDay = weekdayName(1);
  }
  const dayCode = requestedDay || weekdayName(0);
  const info = hoursByDay(dayCode);
  const label = requestedDay ? DAY_LABELS[dayCode] : 'hoje';

  if (!info.row) {
    return 'Nao consegui confirmar o horario agora. Se preferir, posso verificar com a equipe.';
  }
  if (!info.open) {
    const closedTemplate = pickTemplate('business_hours', 'closed');
    if (!requestedDay && closedTemplate) {
      return applyTemplate(closedTemplate, { next_opening: nextOpeningText() }).trim();
    }
    return 'No ' + label + ', estaremos fechados.';
  }
  const hoursTemplate = pickTemplate('business_hours', 'v1') || 'Hoje funcionamos {{today_hours}}.';
  const rendered = applyTemplate(hoursTemplate, { today_hours: info.text });
  if (!requestedDay) return rendered;
  const capitalized = label.charAt(0).toUpperCase() + label.slice(1);
  return rendered.replace(/^Hoje/, capitalized);
}

function buildOrderReply(order) {
  const foundTemplate = pickTemplate('order_status', 'found');
  const notFoundTemplate = pickTemplate('order_status', 'not_found');
  if (!order) {
    return notFoundTemplate || 'Nao encontrei um pedido ativo neste numero. Se tiver o numero do pedido, pode me enviar?';
  }
  const number = toText(order.order_number) || toText(order.id);
  const status = toStatusLabel(order.status);
  const paymentStatus = toStatusLabel(order.payment_status);
  const eta = Number(order.delivery_estimated_time);
  const etaText = Number.isFinite(eta) && eta > 0 ? String(eta) + ' min' : '';
  const parts = [];
  if (number) {
    parts.push('Consultei aqui: o pedido ' + number + ' esta ' + status + '.');
  } else if (status) {
    parts.push('Consultei aqui: seu pedido esta ' + status + '.');
  }
  if (paymentStatus) parts.push('Pagamento: ' + paymentStatus + '.');
  if (etaText) parts.push('Prazo informado: ' + etaText + '.');
  const text = parts.join(' ').replace(/\s+/g, ' ').trim();
  return foundTemplate ? applyTemplate(foundTemplate, { order_status_text: text }) : text;
}

const filteredZones = zones.filter((zone) => normalize(zone.name) !== 'santissimo');

function matchZone(messageNormalized) {
  return filteredZones.find((zone) => {
    const zoneName = normalize(zone.name);
    return zoneName && (messageNormalized.includes(zoneName) || zoneName.includes(messageNormalized));
  });
}

function buildFeeText(zone) {
  if (!zone) return pickTemplate('delivery_fee', 'ask_neighborhood') || 'Qual e o seu bairro? Assim verifico a taxa certa para voce.';
  return applyTemplate(pickTemplate('delivery_fee', 'known') || '{{delivery_fee_text}}', {
    delivery_fee_text: 'Consultei aqui: para ' + zone.name + ', a taxa informada no momento e ' + money(zone.fee) + '.',
  });
}

function buildAreaText(zone) {
  if (!zone) return pickTemplate('delivery_area', 'ask_neighborhood') || 'Qual e o seu bairro ou um ponto de referencia?';
  return applyTemplate(pickTemplate('delivery_area', 'known') || '{{delivery_area_text}}', {
    delivery_area_text: 'Sim. Atendemos ' + zone.name + '.',
  });
}

function buildEtaText(zone) {
  if (!zone) {
    const mins = filteredZones.map((item) => Number(item.estimated_time_min)).filter(Number.isFinite);
    const maxs = filteredZones.map((item) => Number(item.estimated_time_max)).filter(Number.isFinite);
    if (mins.length && maxs.length) {
      const min = Math.min(...mins);
      const max = Math.max(...maxs);
      const text = 'de ' + min + ' a ' + max + ' min, variando por bairro';
      return applyTemplate(pickTemplate('delivery_eta', 'v1') || 'O prazo medio informado no momento e {{delivery_eta_text}}.', {
        delivery_eta_text: text,
      });
    }
    return 'Nao consegui confirmar o prazo agora. Se me disser seu bairro, eu verifico.';
  }
  const min = Number(zone.estimated_time_min);
  const max = Number(zone.estimated_time_max);
  const text = Number.isFinite(min) && Number.isFinite(max)
    ? ('para ' + zone.name + ', o prazo informado e de ' + min + ' a ' + max + ' min')
    : ('para ' + zone.name + ', o prazo informado e de ' + (min || max) + ' min');
  return applyTemplate(pickTemplate('delivery_eta', 'v1') || 'O prazo medio informado no momento e {{delivery_eta_text}}.', {
    delivery_eta_text: text,
  });
}

function paymentMethodsText() {
  const normalizedMethods = Array.from(new Set(paymentRows
    .map((item) => normalize(item.payment_method))
    .filter(Boolean)))
    .map((method) => {
      if (method === 'pix_balcao' || method === 'pix') return 'Pix';
      if (method === 'cartao') return 'cartao';
      if (method === 'dinheiro') return 'dinheiro';
      if (method === 'local') return 'pagamento no local';
      return '';
    })
    .filter(Boolean);

  if (!normalizedMethods.length) {
    return 'Nao consegui confirmar as formas de pagamento agora.';
  }
  const paymentMethods = Array.from(new Set(normalizedMethods)).join(', ');
  return applyTemplate(pickTemplate('payment_methods', 'v1') || 'Aceitamos {{payment_methods}}.', {
    payment_methods: paymentMethods,
  });
}

function menuText() {
