function buildProductText(messageNormalized) {
  const ask = pickTemplate('product_availability', 'ask_product') || 'Qual produto voce quer consultar?';
  let best = null;
  let bestScore = 0;
  for (const product of products) {
    const name = normalize(product.name);
    if (!name) continue;
    let score = 0;
    const words = name.split(' ');
    if (messageNormalized.includes(name)) score += 10;
    for (const word of words) {
      if (word.length >= 3 && messageNormalized.includes(word)) score += 2;
    }
    if (score > bestScore) {
      best = product;
      bestScore = score;
    }
  }
  if (!best || bestScore < 3) return ask;
  const known = pickTemplate('product_availability', 'known') || '{{product_availability_text}}';
  return applyTemplate(known, {
    product_availability_text: 'Consultei aqui: ' + best.name.trim() + ' esta disponivel no momento.',
  });
}

function findOrderByNumber(text) {
  const digits = (toText(text).match(/\d{5,}/g) ?? []).map(String);
  if (!digits.length) return null;
  const orders = [customerContext.active_order, customerContext.latest_order].filter(Boolean);
  return orders.find((order) => digits.includes(toText(order.order_number))) ?? null;
}

function rankIntents(messageNormalized, currentState) {
  const enabledIntents = (botConfig.intents || []).filter((item) => item.enabled !== false);
  const scores = new Map(enabledIntents.map((item) => [item.code, 0]));
  for (const pattern of (botConfig.patterns || []).filter((item) => item.enabled !== false)) {
    if (pattern.context_state && pattern.context_state !== currentState) continue;
    const target = normalize(pattern.pattern);
    if (!target) continue;
    let matched = false;
    if (pattern.pattern_kind === 'keyword') {
      matched = messageNormalized.split(' ').includes(target) || messageNormalized.includes(target);
    } else {
      matched = messageNormalized.includes(target);
    }
    if (!matched) continue;
    const weight = Number(pattern.weight) || 0;
    const signedWeight = pattern.is_negative ? weight * -1 : weight;
    scores.set(pattern.intent_code, (scores.get(pattern.intent_code) || 0) + signedWeight);
  }
  return enabledIntents
    .map((intent) => ({
      ...intent,
      score: Number(scores.get(intent.code) || 0),
    }))
    .sort((a, b) => {
      if (b.score !== a.score) return b.score - a.score;
      return Number(b.priority || 0) - Number(a.priority || 0);
    });
}

const rawMessage = toText(input.final_message_text || input.message_text);
const messageNormalized = normalize(rawMessage);
const imageAnalysisNormalized = normalize(input.image_analysis_text);
const ranked = rankIntents(messageNormalized, sessionState);
const topIntent = ranked[0] ?? null;
const secondIntent = ranked[1] ?? null;
const enabledIntentMap = new Map((botConfig.intents || []).filter((item) => item.enabled !== false).map((item) => [item.code, item]));

let intent = null;
let replyText = '';
let route = 'ai';
