const menuKeywordHint = /\b(cardapio|menu|hamburguer|hamburgueres|burger|burgers|lanche|lanches)\b/.test(messageNormalized);

if (!replyText && !intent && (sessionState === 'aguardando_categoria_menu' || menuKeywordHint)) {
