    if (intent.code === 'pickup_dinein') replyText = pickupText();
    if (intent.code === 'product_availability') replyText = buildProductText(messageNormalized);
    if (intent.code === 'greeting' || intent.code === 'thanks' || intent.code === 'positive_feedback' || intent.code === 'complaint') {
