const source = $('Basic LLM Chain').first().json ?? {};
const context = $('Classificar e Montar Contexto').first().json ?? {};

function extractUsage(value) {
  if (!value || typeof value !== 'object') return null;
  const usage = value.usage ?? value.tokenUsage ?? value.response_metadata?.tokenUsage ?? value.response_metadata?.usage ?? null;
  if (!usage || typeof usage !== 'object') return null;
  return {
    input_tokens: Number(usage.input_tokens ?? usage.prompt_tokens ?? usage.inputTokens ?? 0) || 0,
    cached_input_tokens: Number(usage.cached_input_tokens ?? usage.cachedPromptTokens ?? usage.cachedInputTokens ?? 0) || 0,
    output_tokens: Number(usage.output_tokens ?? usage.completion_tokens ?? usage.outputTokens ?? 0) || 0,
    reasoning_tokens: Number(usage.reasoning_tokens ?? usage.reasoningTokens ?? 0) || 0,
  };
}

function cleanMessage(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function tryParseJson(rawText) {
  const direct = String(rawText ?? '').trim();
  if (!direct) return null;
  const withoutFences = direct.replace(/^\`\`\`(?:json)?\s*/i, '').replace(/\s*\`\`\`$/i, '').trim();
  const candidates = [withoutFences];
  const firstBrace = withoutFences.indexOf('{');
  const lastBrace = withoutFences.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    candidates.push(withoutFences.slice(firstBrace, lastBrace + 1));
  }
  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch (error) {}
  }
  return null;
}

const candidates = [source.text, source.response, source.output, source.message, source.content, source.answer];
const raw = String(candidates.find((value) => typeof value === 'string' && value.trim()) ?? '').trim();
const fallbackText = raw || 'Posso te ajudar com pedido, cardapio ou entrega. O que voce quer ver agora?';
const parsed = tryParseJson(fallbackText);

let messages = [];
let handoff = false;
let jsonValid = false;

if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
  jsonValid = true;
  handoff = parsed.handoff === true;
  messages = Array.isArray(parsed.messages) ? parsed.messages.map(cleanMessage).filter(Boolean).slice(0, 3) : [];
}

if (!messages.length) {
  messages = [cleanMessage(fallbackText)].filter(Boolean).slice(0, 1);
}

const components = Array.isArray(context.usage_components) ? [...context.usage_components] : [];
const usage = extractUsage(source);
if (usage) {
  components.push({
    kind: 'ai_reply',
    model: 'gpt-5-mini',
    ...usage,
  });
}

return [{
  json: {
    ...context,
    usage_components: components,
    final_reply_text: messages.join('\n\n'),
    final_reply_messages: messages,
    final_handoff: handoff,
    ai_json_valid: jsonValid,
  },
}];

const data = $json ?? {};
const categories = (() => { try { return $('Buscar Categorias Cardapio').all().map((item) => item.json).filter(Boolean); } catch (error) { return []; } })();
const menuOptions = (() => { try { return $('Buscar Opcoes Cardapio').all().map((item) => item.json).filter(Boolean); } catch (error) { return []; } })();
const menuLookup = $('Preparar Consulta Cardapio').first().json ?? {};
const menuFallback = (() => { try { return $('Consolidar Fallback Categoria').first().json ?? {}; } catch (error) { return {}; } })();
const sessionState = String(data.session_state ?? '').trim();
const messageText = String(data.ai_message_text ?? data.final_message_text ?? data.message_text ?? '').trim();

function toText(value) {
